import api from './api';

export const obtenerCategorias = async () => {
  const respuesta = await api.get('/categories');
  return respuesta.data;
};

export const crearCategoria = async (datosCategoria) => {
  const respuesta = await api.post('/categories', datosCategoria);
  return respuesta.data;
};

export const borrarCategoria = async (idCategoria) => {
  await api.delete(`/categories/${idCategoria}`);
};
